1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BLOCK_OF_3_PRICE = 60;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	type Item = { type: string; cursed?: boolean; enchantment?: number };
23	type QuoteStep = { type: "quote"; items: Item[] };
24	type Customer = { yearsWithMHPCO: number };
25	type Scenario = { customer?: Customer; steps: QuoteStep[] };
26	
27	function groupByType(items: Item[]): Map<string, Item[]> {
28	  const groups = new Map<string, Item[]>();
29	  for (const item of items) {
30	    const group = groups.get(item.type) ?? [];
31	    group.push(item);
32	    groups.set(item.type, group);
33	  }
34	  return groups;
35	}
36	
37	function isHighlyEnchanted(item: Item): boolean {
38	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
39	}
40	
41	function itemBasePrice(item: Item): number {
42	  return BASE_PREMIUMS[item.type];
43	}
44	
45	function itemPriceWithSurcharges(item: Item): number {
46	  const base = itemBasePrice(item);
47	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
48	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
49	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
50	    : 0;
51	  return base + curseSurcharge + highEnchantmentSurcharge;
52	}
53	
54	function sumGroup(type: string, group: Item[], itemPrice: (item: Item) => number): number {
55	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
56	    return COMPONENT_BLOCK_OF_3_PRICE;
57	  }
58	  return group.reduce((sum, item) => sum + itemPrice(item), 0);
59	}
60	
61	function sumItems(items: Item[], itemPrice: (item: Item) => number): number {
62	  return Array.from(groupByType(items)).reduce(
63	    (total, [type, group]) => total + sumGroup(type, group, itemPrice),
64	    0,
65	  );
66	}
67	
68	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
69	  const { customer, steps } = scenario as Scenario;
70	  const isLoyalCustomer = (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
71	  const results = steps.map((step, index) => {
72	    const policyBase = sumItems(step.items, itemPriceWithSurcharges);
73	    const unmodifiedBase = sumItems(step.items, itemBasePrice);
74	    const firstInsuranceSurcharge = unmodifiedBase * FIRST_INSURANCE_RATE;
75	    const loyaltyDiscount = isLoyalCustomer ? unmodifiedBase * LOYALTY_DISCOUNT_RATE : 0;
76	    const followUpDiscount = index > 0 ? unmodifiedBase * FOLLOW_UP_DISCOUNT_RATE : 0;
77	    const premium =
78	      policyBase - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
79	    return { premium };
80	  });
81	  return { results };
82	}
